import os
import time
import pytest
import can

BCM_STATUS_ID = 0x100
HEADLIGHT_START_BIT = 1

@pytest.fixture(scope="session")
def can_bus():
    bus = can.Bus(interface=os.getenv('CAN_INTERFACE', 'socketcan'), channel=os.getenv('CAN_CHANNEL', 'can0'), bitrate=500000)
    yield bus
    bus.shutdown()

def get_headlight_status(data: bytes) -> int:
    return (data[0] >> HEADLIGHT_START_BIT) & 0x03

def collect_bcm_messages(bus, duration_sec=1.0):
    msgs = []
    end_time = time.time() + duration_sec
    while time.time() < end_time:
        msg = bus.recv(timeout=0.05)
        if msg and msg.arbitration_id == BCM_STATUS_ID: msgs.append(msg)
    return msgs

